export enum DefectType {
  POTHOLE = "Chuqur (Pothole)",
  CRACK = "Yoriq (Crack)",
  OBSTACLE = "To'siq (Obstacle)",
  FADED_MARKINGS = "O'chgan chiziqlar",
  UNKNOWN = "Noma'lum"
}

export enum Severity {
  LOW = "Past",
  MEDIUM = "O'rtacha",
  HIGH = "Yuqori"
}

export interface LocationData {
  lat: number;
  lng: number;
  address?: string;
}

export interface AnalysisResult {
  type: DefectType;
  severity: Severity;
  description: string;
  recommendation: string;
}

export interface Report {
  id: string;
  image?: string;
  textInput?: string;
  location?: LocationData;
  analysis: AnalysisResult;
  timestamp: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, DefectType, Severity } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

const ROAD_ANALYSIS_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    type: {
      type: Type.STRING,
      description: "Type of road defect (Chuqur, Yoriq, To'siq, O'chgan chiziqlar, Noma'lum)",
    },
    severity: {
      type: Type.STRING,
      description: "Severity level (Past, O'rtacha, Yuqori)",
    },
    description: {
      type: Type.STRING,
      description: "A short detailed description of the defect in Uzbek language.",
    },
    recommendation: {
      type: Type.STRING,
      description: "A practical recommendation for road repair or safety in Uzbek language.",
    },
  },
  required: ["type", "severity", "description", "recommendation"],
};

export async function analyzeRoadIssue(
  image?: string,
  text?: string
): Promise<AnalysisResult> {
  const model = "gemini-3-flash-preview";
  const prompt = `Siz yo'l infratuzilmasi bo'yicha mutaxassissiz. 
    ${image ? "Berilgan rasm" : "Berilgan tavsif"} asosida yo'ldagi nosozlikni tahlil qiling. 
    Nosozlik turi, xavflilik darajasi va tavsiflarni aniqlang. 
    Barcha ma'lumotlarni o'zbek tilida taqdim eting.
    ${text ? `Foydalanuvchi tavsifi: "${text}"` : ""}`;

  const contents: any = { parts: [] };

  if (image) {
    contents.parts.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: image.split(",")[1],
      },
    });
  }

  contents.parts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model,
      contents,
      config: {
        responseMimeType: "application/json",
        responseSchema: ROAD_ANALYSIS_SCHEMA,
      },
    });

    const result = JSON.parse(response.text || "{}");

    return {
      type: result.type as DefectType,
      severity: result.severity as Severity,
      description: result.description,
      recommendation: result.recommendation,
    };
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw new Error("Tahlil qilishda xatolik yuz berdi. Iltimos, qaytadan urinib ko'ring.");
  }
}

import React, { useEffect, useRef } from 'react';
import { LocationData } from '../types';

interface MapDisplayProps {
  location: LocationData;
}

const MapDisplay: React.FC<MapDisplayProps> = ({ location }) => {
  const mapContainer = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);

  useEffect(() => {
    if (mapContainer.current && !mapInstance.current) {
      // @ts-ignore
      mapInstance.current = L.map(mapContainer.current).setView([location.lat, location.lng], 15);

      // @ts-ignore
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; OpenStreetMap contributors'
      }).addTo(mapInstance.current);

      // @ts-ignore
      L.marker([location.lat, location.lng]).addTo(mapInstance.current);
    }

    return () => {
      if (mapInstance.current) {
        mapInstance.current.remove();
        mapInstance.current = null;
      }
    };
  }, [location]);

  return (
    <div className="rounded-xl overflow-hidden border border-gray-200 shadow-sm">
      <div ref={mapContainer} className="h-48 w-full z-0"></div>
      <div className="p-3 bg-white text-xs text-gray-500 flex items-center">
        <i className="fas fa-location-dot mr-2 text-blue-500"></i>
        Koordinatalar: {location.lat.toFixed(6)}, {location.lng.toFixed(6)}
      </div>
    </div>
  );
};

export default MapDisplay;

import React, { useState, useCallback, useRef } from 'react';
import Header from './components/Header';
import MapDisplay from './components/MapDisplay';
import { analyzeRoadIssue } from './geminiService';
import { Report, LocationData, Severity } from './types';

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [text, setText] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [reports, setReports] = useState<Report[]>([]);
  const [currentLocation, setCurrentLocation] = useState<LocationData | null>(null);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
      };
      reader.readAsDataURL(file);

      // Get location when image is selected
      if (navigator.geolocation) {
        navigator.geolocation.getCurrentPosition(
          (position) => {
            setCurrentLocation({
              lat: position.coords.latitude,
              lng: position.coords.longitude,
            });
          },
          () => console.warn("Joylashuvni aniqlash imkoni bo'lmadi")
        );
      }
    }
  };

  const handleAnalysis = async () => {
    if (!image && !text.trim()) {
      setError("Iltimos, rasm yuklang yoki tavsif kiriting.");
      return;
    }

    setIsAnalyzing(true);
    setError(null);

    try {
      const result = await analyzeRoadIssue(image || undefined, text || undefined);

      const newReport: Report = {
        id: Date.now().toString(),
        image: image || undefined,
        textInput: text || undefined,
        location: currentLocation || undefined,
        analysis: result,
        timestamp: Date.now(),
      };

      setReports(prev => [newReport, ...prev]);
      // Reset form
      setImage(null);
      setText('');
      if (fileInputRef.current) fileInputRef.current.value = '';
    } catch (err: any) {
      setError(err.message || "Xatolik yuz berdi");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const getSeverityColor = (severity: string) => {
    switch (severity) {
      case 'Yuqori': return 'text-red-600 bg-red-50 border-red-200';
      case "O'rtacha": return 'text-orange-600 bg-orange-50 border-orange-200';
      case 'Past': return 'text-green-600 bg-green-50 border-green-200';
      default: return 'text-gray-600 bg-gray-50 border-gray-200';
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Header />

      <main className="flex-grow max-w-5xl mx-auto w-full px-4 py-8">
        <section className="mb-12 text-center md:text-left">
          <h1 className="text-3xl md:text-4xl font-extrabold text-slate-900 mb-4">
            Yo‘l nosozliklarini aniqlash tizimi
          </h1>
          <p className="text-lg text-slate-600 max-w-2xl leading-relaxed">
            Yo'l yuzasidagi chuqurlar, yoriqlar va boshqa muammolarni sun'iy intellekt yordamida tahlil qiling va hisobot qoldiring.
          </p>
        </section>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Analysis Form */}
          <div className="lg:col-span-1">
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 sticky top-24">
              <h2 className="text-xl font-bold text-slate-900 mb-6 flex items-center">
                <i className="fas fa-plus-circle mr-2 text-blue-600"></i>
                Yangi hisobot
              </h2>

              <div className="space-y-6">
                {/* Image Upload Area */}
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Rasm yuklang</label>
                  <div 
                    onClick={() => fileInputRef.current?.click()}
                    className={`relative cursor-pointer border-2 border-dashed rounded-xl overflow-hidden transition-all h-48 flex flex-col items-center justify-center
                      ${image ? 'border-blue-400' : 'border-slate-200 hover:border-blue-400 bg-slate-50'}`}
                  >
                    {image ? (
                      <img src={image} className="w-full h-full object-cover" alt="Uploaded road issue" />
                    ) : (
                      <div className="text-center p-4">
                        <i className="fas fa-camera text-slate-400 text-3xl mb-2"></i>
                        <p className="text-sm text-slate-500">Rasm yuklash uchun bosing</p>
                      </div>
                    )}
                  </div>
                  <input 
                    type="file" 
                    ref={fileInputRef} 
                    onChange={handleImageChange} 
                    accept="image/*" 
                    className="hidden" 
                  />
                </div>

                {/* Text Description */}
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Qisqacha tavsif (ixtiyoriy)</label>
                  <textarea 
                    value={text}
                    onChange={(e) => setText(e.target.value)}
                    placeholder="Muammo haqida ma'lumot kiriting..."
                    className="w-full rounded-xl border-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all min-h-[100px] text-sm"
                  />
                </div>

                {error && (
                  <div className="p-3 bg-red-50 border border-red-200 rounded-lg text-red-600 text-sm flex items-start">
                    <i className="fas fa-exclamation-circle mt-0.5 mr-2"></i>
                    {error}
                  </div>
                )}

                <button 
                  onClick={handleAnalysis}
                  disabled={isAnalyzing || (!image && !text.trim())}
                  className={`w-full py-4 px-6 rounded-xl font-bold text-white shadow-lg transition-all transform active:scale-95 flex items-center justify-center space-x-2
                    ${isAnalyzing || (!image && !text.trim()) 
                      ? 'bg-slate-300 cursor-not-allowed shadow-none' 
                      : 'bg-blue-600 hover:bg-blue-700 hover:shadow-blue-200'}`}
                >
                  {isAnalyzing ? (
                    <>
                      <i className="fas fa-circle-notch animate-spin"></i>
                      <span>Tahlil qilinmoqda...</span>
                    </>
                  ) : (
                    <>
                      <i className="fas fa-microchip"></i>
                      <span>AI Tahlilini boshlash</span>
                    </>
                  )}
                </button>
              </div>
            </div>
          </div>

          {/* Results Area */}
          <div className="lg:col-span-2 space-y-6">
            <h2 className="text-xl font-bold text-slate-900 flex items-center">
              <i className="fas fa-history mr-2 text-blue-600"></i>
              Natijalar va hisobotlar
            </h2>

            {reports.length === 0 ? (
              <div className="bg-white rounded-2xl border-2 border-dashed border-slate-200 p-12 text-center text-slate-400">
                <i className="fas fa-folder-open text-5xl mb-4"></i>
                <p>Hozircha hisobotlar yo'q. Tahlil qilishni boshlang!</p>
              </div>
            ) : (
              reports.map((report) => (
                <div key={report.id} className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden transition-all hover:shadow-md animate-fade-in">
                  <div className="md:flex">
                    {/* Media section */}
                    <div className="md:w-1/3">
                      {report.image ? (
                        <img src={report.image} alt="Reported defect" className="h-48 md:h-full w-full object-cover" />
                      ) : (
                        <div className="h-48 md:h-full w-full bg-slate-100 flex items-center justify-center">
                          <i className="fas fa-file-alt text-slate-300 text-4xl"></i>
                        </div>
                      )}
                    </div>

                    {/* Content section */}
                    <div className="md:w-2/3 p-6">
                      <div className="flex justify-between items-start mb-4">
                        <div>
                          <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium border ${getSeverityColor(report.analysis.severity)} mb-2`}>
                            {report.analysis.severity} xavf
                          </span>
                          <h3 className="text-xl font-bold text-slate-900">{report.analysis.type}</h3>
                        </div>
                        <span className="text-xs text-slate-400">
                          {new Date(report.timestamp).toLocaleString('uz-UZ')}
                        </span>
                      </div>

                      <p className="text-slate-600 text-sm mb-4 line-clamp-2 italic">
                        "{report.analysis.description}"
                      </p>

                      <div className="bg-blue-50 border border-blue-100 rounded-xl p-3 mb-4">
                        <h4 className="text-xs font-bold text-blue-800 uppercase tracking-wider mb-1 flex items-center">
                          <i className="fas fa-wrench mr-1.5"></i>
                          Tavsiya
                        </h4>
                        <p className="text-blue-700 text-sm">{report.analysis.recommendation}</p>
                      </div>

                      {report.location && (
                        <div className="mt-4">
                          <MapDisplay location={report.location} />
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 py-8 mt-12">
        <div className="max-w-5xl mx-auto px-4 text-center">
          <p className="text-slate-500 text-sm">
            &copy; 2024 RoadAI Tizimi. Barcha huquqlar himoyalangan.
          </p>
          <div className="mt-4 flex justify-center space-x-4">
