import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, DefectType, Severity, RoadHealth } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

const ROAD_ANALYSIS_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    type: {
      type: Type.STRING,
      description: "Nosozlik turi: 'Chuqur (Pothole)', 'Yoriq (Crack)', 'To'siq (Obstacle)', 'O'chgan chiziqlar', 'Tekis yo'l' yoki 'Noma'lum'",
    },
    severity: {
      type: Type.STRING,
      description: "Xavflilik darajasi: 'Past', 'O'rtacha', 'Yuqori' yoki 'Yo'q'",
    },
    health: {
      type: Type.STRING,
      description: "Yo'lning umumiy holati: 'A'lo', 'Yaxshi', 'Qoniqarsiz', 'Yomon'",
    },
    description: {
      type: Type.STRING,
      description: "Yo'l holati haqida qisqa va aniq o'zbekcha tavsif.",
    },
    recommendation: {
      type: Type.STRING,
      description: "Harakat xavfsizligi bo'yicha amaliy tavsiya.",
    },
  },
  required: ["type", "severity", "health", "description", "recommendation"],
};

export async function analyzeRoadIssue(
  image: string,
  mode: 'live' | 'manual' = 'manual'
): Promise<AnalysisResult> {
  const model = "gemini-3-flash-preview";
  const systemInstruction = `Siz yo'l xavfsizligi va infratuzilmasi bo'yicha ilg'or AI mutaxassissiz. 
    Tasvirni tahlil qiling va yo'lning holatini aniqlang. 
    Agar yo'l yaxshi bo'lsa, buni 'Yaxshi' yoki 'A'lo' deb belgilang. 
    Agar nosozliklar (chuqur, yoriq) bo'lsa, ularni aniqlab, 'Yomon' yoki 'Qoniqarsiz' deb baholang.
    Barcha javoblar o'zbek tilida bo'lishi shart.`;

  const contents = [
    {
      parts: [
        {
          inlineData: {
            mimeType: "image/jpeg",
            data: image.split(",")[1],
          },
        },
        { text: "Ushbu yo'l tasvirini tahlil qiling. Yo'l yaxshimi yoki nosoz? Holatni va tavsiyalarni bering." },
      ],
    },
  ];

  try {
    const response = await ai.models.generateContent({
      model,
      contents,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: ROAD_ANALYSIS_SCHEMA,
      },
    });

    const result = JSON.parse(response.text || "{}");

    return {
      type: result.type as DefectType,
      severity: result.severity as Severity,
      health: result.health as RoadHealth,
      description: result.description,
      recommendation: result.recommendation,
    };
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw new Error("Tahlil xatosi.");
  }
}

import React, { useRef, useEffect, useState } from 'react';
import { analyzeRoadIssue } from '../geminiService';
import { AnalysisResult } from '../types';

interface LiveVisionProps {
  onAnalysisUpdate: (result: AnalysisResult, frame: string) => void;
  isActive: boolean;
}

const LiveVision: React.FC<LiveVisionProps> = ({ onAnalysisUpdate, isActive }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  useEffect(() => {
    if (isActive) {
      startCamera();
    } else {
      stopCamera();
    }
    return () => stopCamera();
  }, [isActive]);

  const startCamera = async () => {
    try {
      const s = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' }, 
        audio: false 
      });
      setStream(s);
      if (videoRef.current) {
        videoRef.current.srcObject = s;
      }
    } catch (err) {
      console.error("Kameraga kirishda xatolik:", err);
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
  };

  useEffect(() => {
    let interval: any;
    if (isActive && stream) {
      interval = setInterval(captureAndAnalyze, 5000); // Analyze every 5 seconds
    }
    return () => clearInterval(interval);
  }, [isActive, stream]);

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || isProcessing) return;

    const canvas = canvasRef.current;
    const video = videoRef.current;
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    const imageData = canvas.toDataURL('image/jpeg', 0.7);

    setIsProcessing(true);
    try {
      const result = await analyzeRoadIssue(imageData, 'live');
      onAnalysisUpdate(result, imageData);
    } catch (err) {
      console.error("Live analysis error:", err);
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="relative rounded-2xl overflow-hidden bg-black aspect-video shadow-2xl border-4 border-slate-800">
      <video 
        ref={videoRef} 
        autoPlay 
        playsInline 
        className="w-full h-full object-cover"
      />
      <canvas ref={canvasRef} className="hidden" />

      {/* Scanning Overlay */}
      {isActive && (
        <div className="absolute inset-0 pointer-events-none">
          <div className="absolute top-0 left-0 w-full h-1 bg-blue-500/50 shadow-[0_0_15px_rgba(59,130,246,0.5)] animate-scan"></div>
          <div className="absolute inset-0 border-[20px] border-transparent border-t-blue-500/10 border-b-blue-500/10"></div>

          <div className="absolute top-4 left-4 flex items-center space-x-2">
            <div className="w-3 h-3 bg-red-500 rounded-full animate-pulse"></div>
            <span className="text-white text-xs font-bold uppercase tracking-widest bg-black/40 px-2 py-1 rounded">LIVE AI VISION</span>
          </div>

          {isProcessing && (
            <div className="absolute bottom-4 right-4 bg-blue-600 text-white text-[10px] px-3 py-1 rounded-full animate-bounce">
              TAHLIL QILINMOQDA...
            </div>
          )}
        </div>
      )}

      <style>{`
        @keyframes scan {
          0% { top: 0%; }
          100% { top: 100%; }
        }
        .animate-scan {
          animation: scan 3s linear infinite;
        }
      `}</style>
    </div>
  );
};

export default LiveVision;

import React, { useState, useRef, useEffect } from 'react';
import Header from './components/Header';
import MapDisplay from './components/MapDisplay';
import LiveVision from './components/LiveVision';
import { analyzeRoadIssue } from './geminiService';
import { Report, LocationData, AnalysisResult, RoadHealth } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'live' | 'manual'>('live');
  const [reports, setReports] = useState<Report[]>([]);
  const [currentLocation, setCurrentLocation] = useState<LocationData | null>(null);
  const [lastAnalysis, setLastAnalysis] = useState<AnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.watchPosition(
        (pos) => setCurrentLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
        (err) => console.warn("Joylashuv xatosi:", err),
        { enableHighAccuracy: true }
      );
    }
  }, []);

  const handleLiveUpdate = (result: AnalysisResult, frame: string) => {
    setLastAnalysis(result);

    // Auto-save if it's a critical issue
    if (result.health === RoadHealth.POOR || result.health === RoadHealth.FAIR) {
      const newReport: Report = {
        id: Date.now().toString(),
        image: frame,
        location: currentLocation || undefined,
        analysis: result,
        timestamp: Date.now(),
      };
      setReports(prev => [newReport, ...prev].slice(0, 20)); // Keep last 20
    }
  };

  const handleManualUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsAnalyzing(true);
    setError(null);
    const reader = new FileReader();
    reader.onloadend = async () => {
      try {
        const base64 = reader.result as string;
        const result = await analyzeRoadIssue(base64);
        const newReport: Report = {
          id: Date.now().toString(),
          image: base64,
          location: currentLocation || undefined,
          analysis: result,
          timestamp: Date.now(),
        };
        setReports(prev => [newReport, ...prev]);
        setLastAnalysis(result);
      } catch (err: any) {
        setError("Tahlil qilishda xatolik.");
      } finally {
        setIsAnalyzing(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const getHealthColor = (health: RoadHealth) => {
    switch (health) {
      case RoadHealth.EXCELLENT: return 'bg-emerald-500 text-white';
      case RoadHealth.GOOD: return 'bg-green-500 text-white';
      case RoadHealth.FAIR: return 'bg-amber-500 text-white';
      case RoadHealth.POOR: return 'bg-red-500 text-white';
      default: return 'bg-slate-500 text-white';
    }
  };

  return (
