                onClick={() => setActiveTab('live')}
                className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'live' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
              >
                <i className="fas fa-video mr-2"></i> Jonli Monitoring
              </button>
              <button 
                onClick={() => setActiveTab('manual')}
                className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'manual' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
              >
                <i className="fas fa-upload mr-2"></i> Rasm yuklash
              </button>
            </div>

            {activeTab === 'live' ? (
              <LiveVision isActive={activeTab === 'live'} onAnalysisUpdate={handleLiveUpdate} />
            ) : (
              <div 
                onClick={() => fileInputRef.current?.click()}
                className="bg-slate-800/50 border-2 border-dashed border-slate-700 rounded-2xl h-64 flex flex-col items-center justify-center cursor-pointer hover:border-blue-500 hover:bg-slate-800/80 transition-all"
              >
                <input type="file" ref={fileInputRef} onChange={handleManualUpload} className="hidden" accept="image/*" />
                <div className="bg-blue-600/20 p-4 rounded-full mb-4">
                  <i className="fas fa-cloud-upload-alt text-3xl text-blue-500"></i>
                </div>
                <p className="text-lg font-medium">Yo'l rasmini tanlang</p>
                <p className="text-slate-500 text-sm">Tahlil qilish uchun bosing</p>
                {isAnalyzing && <div className="mt-4 text-blue-400 animate-pulse">Tahlil qilinmoqda...</div>}
              </div>
            )}

            {/* Current Status Dashboard */}
            {lastAnalysis && (
              <div className="bg-slate-800 border border-slate-700 rounded-2xl p-6 shadow-xl animate-fade-in">
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
                  <div className="flex items-center space-x-4">
                    <div className={`text-2xl font-black px-4 py-2 rounded-xl ${getHealthColor(lastAnalysis.health)}`}>
                      {lastAnalysis.health}
                    </div>
                    <div>
                      <h2 className="text-xl font-bold text-white uppercase tracking-tight">{lastAnalysis.type}</h2>
                      <p className="text-slate-400 text-sm">Yo'lning joriy holati</p>
                    </div>
                  </div>
                  <div className="flex items-center space-x-2 bg-slate-900 px-4 py-2 rounded-lg border border-slate-700">
                    <i className="fas fa-shield-alt text-blue-500"></i>
                    <span className="text-xs font-bold uppercase text-slate-400">Xavflilik: </span>
