  FADED_MARKINGS = "O'chgan chiziqlar",
  SMOOTH = "Tekis yo'l",
  UNKNOWN = "Noma'lum"
}

export enum Severity {
  LOW = "Past",
  MEDIUM = "O'rtacha",
  HIGH = "Yuqori",
  NONE = "Yo'q"
}

export enum RoadHealth {
  EXCELLENT = "A'lo",
  GOOD = "Yaxshi",
  FAIR = "Qoniqarsiz",
  POOR = "Yomon"
}

