                      </div>
                    </div>
                    <div className="flex items-center space-x-2 bg-slate-900 px-4 py-2 rounded-lg border border-slate-700">
                      <i className="fas fa-shield-alt text-blue-500"></i>
                      <span className="text-xs font-bold uppercase text-slate-400">Xavflilik: </span>
                      <span className="text-sm font-bold text-white">{lastAnalysis.severity}</span>
                    </div>
                  </div>

                  <div className="grid md:grid-cols-2 gap-6">
                    <div className="space-y-2">
                      <h4 className="text-xs font-bold text-slate-500 uppercase tracking-widest">Tavsif</h4>
                      <p className="text-slate-300 leading-relaxed">{lastAnalysis.description}</p>
                    </div>
                    <div className="space-y-2">
                      <h4 className="text-xs font-bold text-slate-500 uppercase tracking-widest">Tavsiya</h4>
                      <div className="bg-blue-500/10 border border-blue-500/20 p-3 rounded-xl text-blue-400 text-sm">
                        {lastAnalysis.recommendation}
                      </div>
                    </div>
                  </div>
                </div>
              )}
            </div>

            {/* Right Column: History & Map */}
            <div className="lg:col-span-4 space-y-6">
              <div className="bg-slate-800 border border-slate-700 rounded-2xl overflow-hidden">
                <div className="p-4 border-b border-slate-700 flex justify-between items-center">
                  <h3 className="font-bold text-white"><i className="fas fa-map-marker-alt text-red-500 mr-2"></i> Geo-lokatsiya</h3>
                </div>
                {currentLocation && <MapDisplay location={currentLocation} />}
              </div>

              <div className="bg-slate-800 border border-slate-700 rounded-2xl overflow-hidden h-[500px] flex flex-col">
                <div className="p-4 border-b border-slate-700 flex justify-between items-center bg-slate-800/80 sticky top-0 z-10">
                  <h3 className="font-bold text-white"><i className="fas fa-list text-blue-500 mr-2"></i> So'nggi xavflar</h3>
                  <span className="bg-slate-700 text-slate-300 text-[10px] px-2 py-0.5 rounded-full">{reports.length} ta</span>
                </div>

                <div className="flex-grow overflow-y-auto p-4 space-y-4">
                  {reports.length === 0 ? (
                    <div className="text-center py-12 text-slate-600">
                      <i className="fas fa-clipboard-list text-4xl mb-4 opacity-20"></i>
                      <p className="text-sm">Hozircha xavfli yo'llar aniqlanmadi</p>
                    </div>
                  ) : (
                    reports.map(r => (
                      <div key={r.id} className="bg-slate-900/50 border border-slate-800 p-3 rounded-xl hover:bg-slate-900 transition-colors group">
                        <div className="flex space-x-3">
                          <img src={r.image} className="w-16 h-16 rounded-lg object-cover border border-slate-700" alt="Issue" />
                          <div className="flex-grow min-w-0">
                            <div className="flex justify-between items-start">
                              <span className={`text-[9px] px-1.5 py-0.5 rounded uppercase font-black ${getHealthColor(r.analysis.health)}`}>
                                {r.analysis.health}
                              </span>
                              <span className="text-[9px] text-slate-500">{new Date(r.timestamp).toLocaleTimeString()}</span>
                            </div>
                            <h5 className="text-sm font-bold text-slate-200 truncate mt-1">{r.analysis.type}</h5>
                            <p className="text-[10px] text-slate-500 line-clamp-1 mt-1">Yubordi: {r.userName}</p>
                          </div>
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Visual Enhancements */}
      <div className="fixed bottom-0 left-0 w-full h-1/4 bg-gradient-to-t from-blue-900/10 to-transparent pointer-events-none"></div>
    </div>
  );
};

export default App;

export enum DefectType {
  POTHOLE = "Chuqur (Pothole)",
  CRACK = "Yoriq (Crack)",
  OBSTACLE = "To'siq (Obstacle)",
  FADED_MARKINGS = "O'chgan chiziqlar",
  SMOOTH = "Tekis yo'l",
  UNKNOWN = "Noma'lum"
}

export enum Severity {
  LOW = "Past",
  MEDIUM = "O'rtacha",
  HIGH = "Yuqori",
  NONE = "Yo'q"
}

export enum RoadHealth {
  EXCELLENT = "A'lo",
  GOOD = "Yaxshi",
  FAIR = "Qoniqarsiz",
  POOR = "Yomon"
}

export enum UserRole {
  USER = "USER",
  ADMIN = "ADMIN"
}

export interface User {
  id: string;
  name: string;
  phone?: string;
  role: UserRole;
  avatar?: string;
  personalCode?: string;
}

export interface LocationData {
  lat: number;
  lng: number;
  address?: string;
}

export interface AnalysisResult {
  type: DefectType;
  severity: Severity;
  health: RoadHealth;
  description: string;
  recommendation: string;
}

export interface Report {
  id: string;
  userId: string;
  userName: string;
  image?: string;
  location?: LocationData;
  analysis: AnalysisResult;
  timestamp: number;
}

