import React, { useState, useRef, useEffect, useMemo } from 'react';
import Header from './components/Header';
import MapDisplay from './components/MapDisplay';
import LiveVision from './components/LiveVision';
import UserProfile from './components/UserProfile';
import AdminPanel from './components/AdminPanel';
import LoginForm from './components/LoginForm';
import { analyzeRoadIssue } from './geminiService';
import { Report, LocationData, AnalysisResult, RoadHealth, User, UserRole } from './types';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeView, setActiveView] = useState<'monitor' | 'profile' | 'admin'>('monitor');
  const [activeTab, setActiveTab] = useState<'live' | 'manual'>('live');
  const [reports, setReports] = useState<Report[]>([]);
  const [currentLocation, setCurrentLocation] = useState<LocationData | null>(null);
  const [lastAnalysis, setLastAnalysis] = useState<AnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Persistence logic
  useEffect(() => {
    const savedUser = localStorage.getItem('roadai_user');
    const savedReports = localStorage.getItem('roadai_reports');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));
    if (savedReports) setReports(JSON.parse(savedReports));
  }, []);

  useEffect(() => {
    if (currentUser) localStorage.setItem('roadai_user', JSON.stringify(currentUser));
    else localStorage.removeItem('roadai_user');
  }, [currentUser]);

  useEffect(() => {
    localStorage.setItem('roadai_reports', JSON.stringify(reports));
  }, [reports]);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.watchPosition(
        (pos) => setCurrentLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
        (err) => console.warn("Joylashuv xatosi:", err),
        { enableHighAccuracy: true }
      );
    }
  }, []);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setActiveView('monitor');
  };

  const handleLogout = () => {
    setCurrentUser(null);
  };

  const handleLiveUpdate = (result: AnalysisResult, frame: string) => {
    if (!currentUser) return;
    setLastAnalysis(result);

    // Auto-save if it's a critical issue
    if (result.health === RoadHealth.POOR || result.health === RoadHealth.FAIR) {
      const newReport: Report = {
        id: Date.now().toString(),
        userId: currentUser.id,
        userName: currentUser.name,
        image: frame,
        location: currentLocation || undefined,
        analysis: result,
        timestamp: Date.now(),
      };
      setReports(prev => [newReport, ...prev].slice(0, 100)); 
    }
  };

  const handleManualUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!currentUser) return;
    const file = e.target.files?.[0];
    if (!file) return;

    setIsAnalyzing(true);
    setError(null);
    const reader = new FileReader();
    reader.onloadend = async () => {
      try {
        const base64 = reader.result as string;
        const result = await analyzeRoadIssue(base64);
        const newReport: Report = {
          id: Date.now().toString(),
          userId: currentUser.id,
          userName: currentUser.name,
          image: base64,
          location: currentLocation || undefined,
          analysis: result,
          timestamp: Date.now(),
        };
        setReports(prev => [newReport, ...prev]);
        setLastAnalysis(result);
      } catch (err: any) {
        setError("Tahlil qilishda xatolik.");
      } finally {
        setIsAnalyzing(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const getHealthColor = (health: RoadHealth) => {
    switch (health) {
      case RoadHealth.EXCELLENT: return 'bg-emerald-500 text-white';
      case RoadHealth.GOOD: return 'bg-green-500 text-white';
      case RoadHealth.FAIR: return 'bg-amber-500 text-white';
      case RoadHealth.POOR: return 'bg-red-500 text-white';
      default: return 'bg-slate-500 text-white';
    }
  };

  const userReports = useMemo(() => reports.filter(r => r.userId === currentUser?.id), [reports, currentUser]);

  if (!currentUser) {
    return <LoginForm onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-200">
      <Header user={currentUser} onLogout={handleLogout} />

      {/* Navigation Menu */}
      <div className="bg-slate-900/50 border-b border-slate-800 sticky top-16 z-40 backdrop-blur-md">
        <div className="max-w-6xl mx-auto px-4 flex space-x-8">
          <button 
            onClick={() => setActiveView('monitor')}
            className={`py-4 text-xs font-bold uppercase tracking-widest border-b-2 transition-all ${activeView === 'monitor' ? 'border-blue-500 text-blue-500' : 'border-transparent text-slate-500 hover:text-slate-300'}`}
          >
            <i className="fas fa-desktop mr-2"></i> Monitoring
          </button>
          <button 
            onClick={() => setActiveView('profile')}
            className={`py-4 text-xs font-bold uppercase tracking-widest border-b-2 transition-all ${activeView === 'profile' ? 'border-blue-500 text-blue-500' : 'border-transparent text-slate-500 hover:text-slate-300'}`}
          >
            <i className="fas fa-user mr-2"></i> Profil
          </button>
          {currentUser.role === UserRole.ADMIN && (
            <button 
              onClick={() => setActiveView('admin')}
              className={`py-4 text-xs font-bold uppercase tracking-widest border-b-2 transition-all ${activeView === 'admin' ? 'border-blue-500 text-blue-500' : 'border-transparent text-slate-500 hover:text-slate-300'}`}
            >
              <i className="fas fa-shield-alt mr-2"></i> Admin Panel
            </button>
          )}
        </div>
      </div>

      <main className="max-w-6xl mx-auto px-4 py-8">

        {activeView === 'profile' && (
          <UserProfile user={currentUser} userReports={userReports} />
        )}

        {activeView === 'admin' && (
          <AdminPanel allReports={reports} />
        )}

        {activeView === 'monitor' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 animate-fade-in">
            {/* Left Column: Analysis & Controls */}
            <div className="lg:col-span-8 space-y-6">

              {/* Mode Switcher */}
              <div className="bg-slate-800/50 p-1 rounded-xl flex w-fit border border-slate-700">
                <button 
                  onClick={() => setActiveTab('live')}
                  className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'live' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
                >
                  <i className="fas fa-video mr-2"></i> Jonli Monitoring
                </button>
                <button 
                  onClick={() => setActiveTab('manual')}
                  className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'manual' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
                >
                  <i className="fas fa-upload mr-2"></i> Rasm yuklash
                </button>
              </div>

              {activeTab === 'live' ? (
                <LiveVision isActive={activeTab === 'live'} onAnalysisUpdate={handleLiveUpdate} />
              ) : (
                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className="bg-slate-800/50 border-2 border-dashed border-slate-700 rounded-2xl h-64 flex flex-col items-center justify-center cursor-pointer hover:border-blue-500 hover:bg-slate-800/80 transition-all"
                >
                  <input type="file" ref={fileInputRef} onChange={handleManualUpload} className="hidden" accept="image/*" />
                  <div className="bg-blue-600/20 p-4 rounded-full mb-4">
                    <i className="fas fa-cloud-upload-alt text-3xl text-blue-500"></i>
                  </div>
                  <p className="text-lg font-medium">Yo'l rasmini tanlang</p>
                  <p className="text-slate-500 text-sm">Tahlil qilish uchun bosing</p>
                  {isAnalyzing && <div className="mt-4 text-blue-400 animate-pulse">Tahlil qilinmoqda...</div>}
                </div>
              )}

              {lastAnalysis && (
                <div className="bg-slate-800 border border-slate-700 rounded-2xl p-6 shadow-xl animate-fade-in">
                  <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
                    <div className="flex items-center space-x-4">
                      <div className={`text-2xl font-black px-4 py-2 rounded-xl ${getHealthColor(lastAnalysis.health)}`}>
                        {lastAnalysis.health}
                      </div>
                      <div>
                        <h2 className="text-xl font-bold text-white uppercase tracking-tight">{lastAnalysis.type}</h2>
                        <p className="text-slate-400 text-sm">Yo'lning joriy holati</p>
                      </div>
                    </div>
                    <div className="flex items-center space-x-2 bg-slate-900 px-4 py-2 rounded-lg border border-slate-700">
                      <i className="fas fa-shield-alt text-blue-500"></i>
                      <span className="text-xs font-bold uppercase text-slate-400">Xavflilik: </span>
                      <span className="text-sm font-bold text-white">{lastAnalysis.severity}</span>
                    </div>
                  </div>

                  <div className="grid md:grid-cols-2 gap-6">
                    <div className="space-y-2">
                      <h4 className="text-xs font-bold text-slate-500 uppercase tracking-widest">Tavsif</h4>
                      <p className="text-slate-300 leading-relaxed">{lastAnalysis.description}</p>
                    </div>
                    <div className="space-y-2">
                      <h4 className="text-xs font-bold text-slate-500 uppercase tracking-widest">Tavsiya</h4>
                      <div className="bg-blue-500/10 border border-blue-500/20 p-3 rounded-xl text-blue-400 text-sm">
                        {lastAnalysis.recommendation}
                      </div>
                    </div>
                  </div>
                </div>
              )}
            </div>

            {/* Right Column: History & Map */}
            <div className="lg:col-span-4 space-y-6">
              <div className="bg-slate-800 border border-slate-700 rounded-2xl overflow-hidden">
                <div className="p-4 border-b border-slate-700 flex justify-between items-center">
                  <h3 className="font-bold text-white"><i className="fas fa-map-marker-alt text-red-500 mr-2"></i> Geo-lokatsiya</h3>
                </div>
                {currentLocation && <MapDisplay location={currentLocation} />}
              </div>

              <div className="bg-slate-800 border border-slate-700 rounded-2xl overflow-hidden h-[500px] flex flex-col">
                <div className="p-4 border-b border-slate-700 flex justify-between items-center bg-slate-800/80 sticky top-0 z-10">
                  <h3 className="font-bold text-white"><i className="fas fa-list text-blue-500 mr-2"></i> So'nggi xavflar</h3>
                  <span className="bg-slate-700 text-slate-300 text-[10px] px-2 py-0.5 rounded-full">{reports.length} ta</span>
                </div>

                <div className="flex-grow overflow-y-auto p-4 space-y-4">
                  {reports.length === 0 ? (
                    <div className="text-center py-12 text-slate-600">
                      <i className="fas fa-clipboard-list text-4xl mb-4 opacity-20"></i>
                      <p className="text-sm">Hozircha xavfli yo'llar aniqlanmadi</p>
                    </div>
                  ) : (
                    reports.map(r => (
                      <div key={r.id} className="bg-slate-900/50 border border-slate-800 p-3 rounded-xl hover:bg-slate-900 transition-colors group">
                        <div className="flex space-x-3">
                          <img src={r.image} className="w-16 h-16 rounded-lg object-cover border border-slate-700" alt="Issue" />
                          <div className="flex-grow min-w-0">
                            <div className="flex justify-between items-start">
                              <span className={`text-[9px] px-1.5 py-0.5 rounded uppercase font-black ${getHealthColor(r.analysis.health)}`}>
                                {r.analysis.health}
                              </span>
                              <span className="text-[9px] text-slate-500">{new Date(r.timestamp).toLocaleTimeString()}</span>
                            </div>
                            <h5 className="text-sm font-bold text-slate-200 truncate mt-1">{r.analysis.type}</h5>
                            <p className="text-[10px] text-slate-500 line-clamp-1 mt-1">Yubordi: {r.userName}</p>
                          </div>
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Visual Enhancements */}
      <div className="fixed bottom-0 left-0 w-full h-1/4 bg-gradient-to-t from-blue-900/10 to-transparent pointer-events-none"></div>
    </div>
  );
};

