export enum DefectType {
  POTHOLE = "Chuqur (Pothole)",
  CRACK = "Yoriq (Crack)",
  OBSTACLE = "To'siq (Obstacle)",
  FADED_MARKINGS = "O'chgan chiziqlar",
  SMOOTH = "Tekis yo'l",
  UNKNOWN = "Noma'lum"
}

export enum Severity {
  LOW = "Past",
  MEDIUM = "O'rtacha",
  HIGH = "Yuqori",
  NONE = "Yo'q"
}

export enum RoadHealth {
  EXCELLENT = "A'lo",
  GOOD = "Yaxshi",
  FAIR = "Qoniqarsiz",
  POOR = "Yomon"
}

export enum UserRole {
  USER = "USER",
  ADMIN = "ADMIN"
}

export interface User {
  id: string;
  name: string;
  phone?: string;
  role: UserRole;
  avatar?: string;
  personalCode?: string;
}

export interface LocationData {
  lat: number;
  lng: number;
  address?: string;
}

export interface RouteData {
  distance: number; // in meters
  duration: number; // in seconds
  coordinates: [number, number][];
}

export interface AnalysisResult {
  type: DefectType;
  severity: Severity;
  health: RoadHealth;
  description: string;
  recommendation: string;
}

export interface Report {
  id: string;
  userId: string;
  userName: string;
  image?: string;
  location?: LocationData;
  analysis: AnalysisResult;
  timestamp: number;
}

import React, { useEffect, useRef, useState } from 'react';
import { LocationData, RouteData } from '../types';

interface MapDisplayProps {
  currentLocation: LocationData;
  destination?: LocationData | null;
  onRouteFound?: (route: RouteData) => void;
}

const MapDisplay: React.FC<MapDisplayProps> = ({ currentLocation, destination, onRouteFound }) => {
  const mapContainer = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<any>(null);
  const routeLayer = useRef<any>(null);
  const markersGroup = useRef<any>(null);

  useEffect(() => {
    if (mapContainer.current && !mapInstance.current) {
      // @ts-ignore
      mapInstance.current = L.map(mapContainer.current, {
        zoomControl: false,
        attributionControl: false
      }).setView([currentLocation.lat, currentLocation.lng], 15);

      // @ts-ignore
      L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
        maxZoom: 19
      }).addTo(mapInstance.current);

      // @ts-ignore
      markersGroup.current = L.layerGroup().addTo(mapInstance.current);
    }

    return () => {
      if (mapInstance.current) {
        mapInstance.current.remove();
        mapInstance.current = null;
      }
    };
  }, []);

  // Update current location marker
  useEffect(() => {
    if (!mapInstance.current || !markersGroup.current) return;

    markersGroup.current.clearLayers();

    // User Marker
    // @ts-ignore
    const userIcon = L.divIcon({
      className: 'custom-div-icon',
      html: `<div class="w-4 h-4 bg-blue-500 rounded-full border-2 border-white shadow-[0_0_10px_rgba(59,130,246,0.8)] animate-pulse"></div>`,
      iconSize: [16, 16],
      iconAnchor: [8, 8]
    });
    // @ts-ignore
    L.marker([currentLocation.lat, currentLocation.lng], { icon: userIcon }).addTo(markersGroup.current);

    if (destination) {
      // Destination Marker
      // @ts-ignore
      const destIcon = L.divIcon({
        className: 'custom-div-icon',
        html: `<div class="text-red-500 text-2xl"><i class="fas fa-map-marker-alt"></i></div>`,
        iconSize: [24, 24],
        iconAnchor: [12, 24]
      });
      // @ts-ignore
      L.marker([destination.lat, destination.lng], { icon: destIcon }).addTo(markersGroup.current);

      fetchRoute(currentLocation, destination);
    } else {
      if (routeLayer.current) {
        mapInstance.current.removeLayer(routeLayer.current);
        routeLayer.current = null;
      }
      mapInstance.current.setView([currentLocation.lat, currentLocation.lng], 15);
    }
  }, [currentLocation, destination]);

  const fetchRoute = async (start: LocationData, end: LocationData) => {
    try {
      const response = await fetch(
        `https://router.project-osrm.org/route/v1/driving/${start.lng},${start.lat};${end.lng},${end.lat}?overview=full&geometries=geojson`
      );
      const data = await response.json();

      if (data.code === 'Ok') {
        const route = data.routes[0];
        const coordinates = route.geometry.coordinates.map((c: any) => [c[1], c[0]]);

        if (routeLayer.current) {
          mapInstance.current.removeLayer(routeLayer.current);
        }

        // @ts-ignore
        routeLayer.current = L.polyline(coordinates, {
          color: '#3b82f6',
          weight: 6,
          opacity: 0.8,
          lineJoin: 'round',
          className: 'route-path'
        }).addTo(mapInstance.current);

        // Zoom to fit route
        mapInstance.current.fitBounds(routeLayer.current.getBounds(), { padding: [50, 50] });

        if (onRouteFound) {
          onRouteFound({
            distance: route.distance,
            duration: route.duration,
            coordinates
          });
        }
      }
    } catch (error) {
      console.error("Routing error:", error);
    }
  };

  return (
    <div className="relative w-full h-full">
      <div ref={mapContainer} className="h-full w-full z-0"></div>

      <style>{`
        .route-path {
          filter: drop-shadow(0 0 8px rgba(59, 130, 246, 0.6));
        }
      `}</style>
    </div>
  );
};

export default MapDisplay;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import Header from './components/Header';
import MapDisplay from './components/MapDisplay';
import LiveVision from './components/LiveVision';
import UserProfile from './components/UserProfile';
import AdminPanel from './components/AdminPanel';
import LoginForm from './components/LoginForm';
import { analyzeRoadIssue } from './geminiService';
import { Report, LocationData, AnalysisResult, RoadHealth, User, UserRole, RouteData } from './types';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeView, setActiveView] = useState<'monitor' | 'profile' | 'admin'>('monitor');
  const [activeTab, setActiveTab] = useState<'live' | 'manual'>('live');
  const [reports, setReports] = useState<Report[]>([]);
  const [currentLocation, setCurrentLocation] = useState<LocationData | null>(null);
  const [destination, setDestination] = useState<LocationData | null>(null);
  const [routeInfo, setRouteInfo] = useState<RouteData | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [lastAnalysis, setLastAnalysis] = useState<AnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('roadai_user');
    const savedReports = localStorage.getItem('roadai_reports');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));
    if (savedReports) setReports(JSON.parse(savedReports));

    if (navigator.geolocation) {
      navigator.geolocation.watchPosition(
        (pos) => setCurrentLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
        (err) => console.warn("Joylashuv xatosi:", err),
        { enableHighAccuracy: true }
      );
    }
  }, []);

  const handleSearchAddress = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;

    setIsSearching(true);
    try {
      const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(searchQuery)}&limit=1`);
      const data = await response.json();
      if (data && data.length > 0) {
        setDestination({
          lat: parseFloat(data[0].lat),
          lng: parseFloat(data[0].lon),
          address: data[0].display_name
        });
      }
    } catch (error) {
      console.error("Search error:", error);
    } finally {
      setIsSearching(false);
    }
  };

  const handleLogin = (user: User) => setCurrentUser(user);
  const handleLogout = () => setCurrentUser(null);

  const handleLiveUpdate = (result: AnalysisResult, frame: string) => {
    if (!currentUser) return;
    setLastAnalysis(result);
    if (result.health === RoadHealth.POOR || result.health === RoadHealth.FAIR) {
      const newReport: Report = {
        id: Date.now().toString(),
        userId: currentUser.id,
        userName: currentUser.name,
        image: frame,
        location: currentLocation || undefined,
        analysis: result,
        timestamp: Date.now(),
      };
      setReports(prev => [newReport, ...prev].slice(0, 100));
    }
  };

  const userReports = useMemo(() => reports.filter(r => r.userId === currentUser?.id), [reports, currentUser]);

  if (!currentUser) return <LoginForm onLogin={handleLogin} />;

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-200">
      <Header user={currentUser} onLogout={handleLogout} />

      {/* Navigation Menu */}
      <div className="bg-slate-900/50 border-b border-slate-800 sticky top-16 z-40 backdrop-blur-md">
        <div className="max-w-6xl mx-auto px-4 flex space-x-8">
          <button onClick={() => setActiveView('monitor')} className={`py-4 text-xs font-bold uppercase tracking-widest border-b-2 transition-all ${activeView === 'monitor' ? 'border-blue-500 text-blue-500' : 'border-transparent text-slate-500 hover:text-slate-300'}`}>
            <i className="fas fa-desktop mr-2"></i> Monitoring
          </button>
          <button onClick={() => setActiveView('profile')} className={`py-4 text-xs font-bold uppercase tracking-widest border-b-2 transition-all ${activeView === 'profile' ? 'border-blue-500 text-blue-500' : 'border-transparent text-slate-500 hover:text-slate-300'}`}>
            <i className="fas fa-user mr-2"></i> Profil
          </button>
          {currentUser.role === UserRole.ADMIN && (
            <button onClick={() => setActiveView('admin')} className={`py-4 text-xs font-bold uppercase tracking-widest border-b-2 transition-all ${activeView === 'admin' ? 'border-blue-500 text-blue-500' : 'border-transparent text-slate-500 hover:text-slate-300'}`}>
              <i className="fas fa-shield-alt mr-2"></i> Admin Panel
            </button>
          )}
        </div>
      </div>

      <main className="max-w-7xl mx-auto px-4 py-6">
        {activeView === 'profile' && <UserProfile user={currentUser} userReports={userReports} />}
        {activeView === 'admin' && <AdminPanel allReports={reports} />}

        {activeView === 'monitor' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-[calc(100vh-180px)]">

            {/* Left Column: Live Camera & Stats */}
            <div className="lg:col-span-7 flex flex-col space-y-4 h-full overflow-y-auto pr-2">
              <div className="flex space-x-2 bg-slate-800/50 p-1 rounded-xl w-fit border border-slate-700 mb-2">
                <button onClick={() => setActiveTab('live')} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${activeTab === 'live' ? 'bg-blue-600 text-white' : 'text-slate-400'}`}>LIVE VISION</button>
                <button onClick={() => setActiveTab('manual')} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${activeTab === 'manual' ? 'bg-blue-600 text-white' : 'text-slate-400'}`}>GALLERY</button>
              </div>

              <LiveVision isActive={activeTab === 'live'} onAnalysisUpdate={handleLiveUpdate} />

              {lastAnalysis && (
                <div className="bg-slate-800/80 border border-slate-700 rounded-2xl p-5 shadow-xl">
                  <div className="flex items-center justify-between mb-4">
                    <div className="flex items-center space-x-3">
                      <div className={`text-lg font-black px-3 py-1 rounded-lg ${lastAnalysis.health === RoadHealth.POOR ? 'bg-red-500' : 'bg-emerald-500'}`}>{lastAnalysis.health}</div>
                      <h2 className="text-lg font-bold text-white uppercase">{lastAnalysis.type}</h2>
                    </div>
                    <div className="text-[10px] font-bold text-slate-500 uppercase">XAVF: <span className="text-white">{lastAnalysis.severity}</span></div>
                  </div>
                  <p className="text-sm text-slate-300 leading-snug">{lastAnalysis.description}</p>
                </div>
              )}

              <div className="bg-slate-800/50 border border-slate-700 rounded-2xl p-4 flex-grow overflow-y-auto">
                <h3 className="text-xs font-bold text-slate-500 uppercase mb-4 tracking-widest">So'nggi hodisalar</h3>
                <div className="space-y-3">
                  {reports.length === 0 ? <p className="text-xs text-slate-600 italic">Hozircha xavf yo'q...</p> : 
                    reports.slice(0, 5).map(r => (
                      <div key={r.id} className="flex items-center space-x-3 bg-slate-900/50 p-2 rounded-xl border border-slate-800">
                        <img src={r.image} className="w-10 h-10 rounded-lg object-cover" />
                        <div className="flex-grow">
                          <p className="text-xs font-bold text-white">{r.analysis.type}</p>
                          <p className="text-[10px] text-slate-500">{new Date(r.timestamp).toLocaleTimeString()}</p>
                        </div>
                      </div>
                    ))
                  }
                </div>
              </div>
            </div>

            {/* Right Column: Navigation & Map */}
            <div className="lg:col-span-5 flex flex-col space-y-4 h-full">
              {/* Search Bar */}
              <form onSubmit={handleSearchAddress} className="relative z-10">
                <input 
                  type="text" 
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  placeholder="Qayerga boramiz? (Manzilni kiriting)" 
                  className="w-full bg-slate-800/90 border border-slate-700 rounded-2xl py-4 pl-12 pr-4 text-sm text-white focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500 shadow-2xl backdrop-blur-md"
                />
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500">
                  <i className={`fas ${isSearching ? 'fa-spinner fa-spin' : 'fa-search'}`}></i>
                </span>
                {destination && (
                  <button type="button" onClick={() => {setDestination(null); setRouteInfo(null); setSearchQuery('');}} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 hover:text-white">
                    <i className="fas fa-times"></i>
                  </button>
                )}
              </form>

              <div className="bg-slate-800 border border-slate-700 rounded-3xl overflow-hidden flex-grow shadow-2xl relative">
                {currentLocation && (
                  <MapDisplay 
                    currentLocation={currentLocation} 
                    destination={destination} 
                    onRouteFound={setRouteInfo} 
                  />
                )}

                {/* Route Overlay Info */}
                {routeInfo && (
                  <div className="absolute bottom-6 left-6 right-6 bg-slate-900/90 backdrop-blur-md border border-slate-700 p-4 rounded-2xl flex items-center justify-between animate-fade-in z-20">
                    <div className="flex items-center space-x-4">
                      <div className="bg-blue-600/20 p-3 rounded-xl">
                        <i className="fas fa-location-arrow text-blue-500"></i>
                      </div>
                      <div>
                        <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Masofa</p>
                        <p className="text-xl font-black text-white">{(routeInfo.distance / 1000).toFixed(1)} km</p>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Vaqt</p>
                      <p className="text-xl font-black text-emerald-500">{Math.ceil(routeInfo.duration / 60)} daqiqa</p>
                    </div>
                  </div>
                )}
              </div>
            </div>

          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import Header from './components/Header';
import MapDisplay from './components/MapDisplay';
import LiveVision from './components/LiveVision';
import UserProfile from './components/UserProfile';
import AdminPanel from './components/AdminPanel';
import LoginForm from './components/LoginForm';
import { analyzeRoadIssue } from './geminiService';
import { Report, LocationData, AnalysisResult, RoadHealth, User, UserRole, RouteData } from './types';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeView, setActiveView] = useState<'monitor' | 'profile' | 'admin'>('monitor');
  const [activeTab, setActiveTab] = useState<'live' | 'manual'>('live');
  const [reports, setReports] = useState<Report[]>([]);
  const [currentLocation, setCurrentLocation] = useState<LocationData | null>(null);
  const [destination, setDestination] = useState<LocationData | null>(null);
  const [routeInfo, setRouteInfo] = useState<RouteData | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [lastAnalysis, setLastAnalysis] = useState<AnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('roadai_user');
    const savedReports = localStorage.getItem('roadai_reports');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));
    if (savedReports) setReports(JSON.parse(savedReports));

    if (navigator.geolocation) {
      navigator.geolocation.watchPosition(
        (pos) => setCurrentLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
        (err) => console.warn("Joylashuv xatosi:", err),
        { enableHighAccuracy: true }
      );
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('roadai_reports', JSON.stringify(reports));
  }, [reports]);

  const handleSearchAddress = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;

    setIsSearching(true);
    try {
      const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(searchQuery)}&limit=1`);
      const data = await response.json();
      if (data && data.length > 0) {
        setDestination({
          lat: parseFloat(data[0].lat),
          lng: parseFloat(data[0].lon),
          address: data[0].display_name
        });
      }
    } catch (error) {
      console.error("Search error:", error);
    } finally {
      setIsSearching(false);
    }
  };

  const handleLogin = (user: User) => setCurrentUser(user);
  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('roadai_user');
  };

  const deleteReport = (id: string) => {
    if (window.confirm("Haqiqatan ham ushbu hisobotni o'chirmoqchimisiz?")) {
      setReports(prev => prev.filter(r => r.id !== id));
    }
  };

  const handleLiveUpdate = (result: AnalysisResult, frame: string) => {
    if (!currentUser) return;
    setLastAnalysis(result);
    // Avtomatik saqlash (faqat yomon yo'llar uchun)
    if (result.health === RoadHealth.POOR || result.health === RoadHealth.FAIR) {
      const newReport: Report = {
        id: Date.now().toString(),
        userId: currentUser.id,
        userName: currentUser.name,
        image: frame,
        location: currentLocation || undefined,
        analysis: result,
        timestamp: Date.now(),
      };
      setReports(prev => [newReport, ...prev].slice(0, 200));
    }
  };

  const userReports = useMemo(() => reports.filter(r => r.userId === currentUser?.id), [reports, currentUser]);

