import React, { useRef, useEffect, useState } from 'react';
import { analyzeRoadIssue } from '../geminiService';
import { AnalysisResult } from '../types';

interface LiveVisionProps {
  onAnalysisUpdate: (result: AnalysisResult, frame: string) => void;
  isActive: boolean;
}

const LiveVision: React.FC<LiveVisionProps> = ({ onAnalysisUpdate, isActive }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [fps, setFps] = useState(0);

  useEffect(() => {
    if (isActive) {
      startCamera();
      const fpsInterval = setInterval(() => {
        setFps(Math.floor(Math.random() * (31 - 28) + 28));
      }, 1000);
      return () => {
        stopCamera();
        clearInterval(fpsInterval);
      };
    } else {
      stopCamera();
    }
  }, [isActive]);

  const startCamera = async () => {
    try {
      const s = await navigator.mediaDevices.getUserMedia({ 
        video: { 
          facingMode: 'environment',
          width: { ideal: 1920 },
          height: { ideal: 1080 }
        }, 
        audio: false 
      });
      setStream(s);
      if (videoRef.current) {
        videoRef.current.srcObject = s;
      }
    } catch (err) {
      console.error("Kameraga kirishda xatolik:", err);
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
  };

  useEffect(() => {
    let interval: any;
    if (isActive && stream) {
      interval = setInterval(captureAndAnalyze, 5000); 
    }
    return () => clearInterval(interval);
  }, [isActive, stream]);

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || isProcessing) return;

    const canvas = canvasRef.current;
    const video = videoRef.current;
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    const imageData = canvas.toDataURL('image/jpeg', 0.6);

    setIsProcessing(true);
    try {
      const result = await analyzeRoadIssue(imageData, 'live');
      onAnalysisUpdate(result, imageData);
    } catch (err) {
      console.error("Live analysis error:", err);
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="relative rounded-[2rem] overflow-hidden bg-black aspect-video shadow-[0_25px_50px_-12px_rgba(0,0,0,1)] border-4 border-slate-900 ring-1 ring-white/5 group">
      <video 
        ref={videoRef} 
        autoPlay 
        playsInline 
        className="w-full h-full object-cover scale-105"
      />
      <canvas ref={canvasRef} className="hidden" />

      {/* HUD Overlay */}
      {isActive && (
        <div className="absolute inset-0 pointer-events-none p-6 flex flex-col justify-between">

          {/* Top HUD */}
          <div className="flex justify-between items-start opacity-70 group-hover:opacity-100 transition-opacity">
            <div className="space-y-1">
               <div className="flex items-center space-x-2 text-[10px] font-black text-white/50 tracking-widest uppercase">
                 <i className="fas fa-wifi text-emerald-500 animate-pulse"></i>
                 <span>Stream Connection: 12ms</span>
               </div>
               <div className="text-emerald-500 font-mono text-[9px] tracking-widest uppercase">AI ENGINE: v2.5.0-ALPHA</div>
            </div>
            <div className="text-right">
               <div className="text-white font-mono text-xs">{new Date().toLocaleTimeString()}</div>
               <div className="text-white/40 font-mono text-[9px] uppercase tracking-widest">{fps} FPS</div>
            </div>
          </div>

          {/* Center Scan Area */}
          <div className="absolute inset-0 flex items-center justify-center">
             <div className="w-1/2 h-1/2 border border-blue-500/20 rounded-3xl relative">
                <div className="absolute top-0 left-0 w-4 h-4 border-t-2 border-l-2 border-blue-500"></div>
                <div className="absolute top-0 right-0 w-4 h-4 border-t-2 border-r-2 border-blue-500"></div>
                <div className="absolute bottom-0 left-0 w-4 h-4 border-b-2 border-l-2 border-blue-500"></div>
                <div className="absolute bottom-0 right-0 w-4 h-4 border-b-2 border-r-2 border-blue-500"></div>
                <div className="absolute top-0 left-0 w-full h-[2px] bg-blue-500/50 shadow-[0_0_15px_rgba(59,130,246,0.8)] animate-scan"></div>
             </div>
          </div>

          {/* Bottom HUD */}
          <div className="flex justify-between items-end">
            <div className="bg-black/40 backdrop-blur-md p-3 rounded-2xl border border-white/5">
               <div className="text-[8px] font-black text-white/30 uppercase mb-1 tracking-widest">Vision Data</div>
               <div className="flex space-x-4">
                  <div className="flex flex-col">
                    <span className="text-[10px] text-white/60 font-bold uppercase">ISO 200</span>
                  </div>
                  <div className="flex flex-col">
                    <span className="text-[10px] text-white/60 font-bold uppercase">f/1.8</span>
                  </div>
                  <div className="flex flex-col">
                    <span className="text-[10px] text-white/60 font-bold uppercase">Auto-WB</span>
                  </div>
               </div>
            </div>

            {isProcessing && (
              <div className="bg-blue-600 px-6 py-2 rounded-xl text-white text-[10px] font-black uppercase tracking-widest shadow-2xl animate-pulse">
                Processing Frame...
              </div>
            )}
          </div>
        </div>
      )}

      <style>{`
        @keyframes scan {
          0% { top: 0%; opacity: 0; }
          10% { opacity: 1; }
          90% { opacity: 1; }
          100% { top: 100%; opacity: 0; }
        }
        .animate-scan {
          animation: scan 4s linear infinite;
        }
      `}</style>
    </div>
  );
};

export default LiveVision;

