            <i className="fas fa-satellite-dish mr-2 text-sm"></i> Monitoring
          </button>
          <button onClick={() => setActiveView('profile')} className={`py-4 text-[10px] font-black uppercase tracking-widest border-b-2 transition-all flex items-center ${activeView === 'profile' ? 'border-blue-500 text-blue-400' : 'border-transparent text-slate-500 hover:text-slate-300'}`}>
            <i className="fas fa-id-card mr-2 text-sm"></i> Profil
          </button>
          {currentUser.role === UserRole.ADMIN && (
            <button onClick={() => setActiveView('admin')} className={`py-4 text-[10px] font-black uppercase tracking-widest border-b-2 transition-all flex items-center ${activeView === 'admin' ? 'border-blue-500 text-blue-400' : 'border-transparent text-slate-500 hover:text-slate-300'}`}>
              <i className="fas fa-shield-halved mr-2 text-sm"></i> Admin Panel
