          )}
        </div>
      </div>

      <main className="max-w-7xl mx-auto px-4 py-6">
        {quotaError && (
          <div className="mb-6 bg-red-500/10 border border-red-500/20 p-4 rounded-2xl flex items-center justify-between animate-fade-in">
            <div className="flex items-center space-x-3 text-red-500">
              <i className="fas fa-triangle-exclamation text-xl"></i>
              <p className="text-sm font-black uppercase tracking-widest">AI Limitiga yetildi. Iltimos biroz kuting (429 Error).</p>
            </div>
            <button onClick={() => setQuotaError(false)} className="text-red-500/50 hover:text-red-500"><i className="fas fa-xmark"></i></button>
          </div>
        )}

        {activeView === 'profile' && <UserProfile user={currentUser} userReports={userReports} onDelete={deleteReport} />}
        {activeView === 'admin' && <AdminPanel allReports={reports} onDelete={deleteReport} />}

        {activeView === 'monitor' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 h-full min-h-[700px]">
            <div className="lg:col-span-7 flex flex-col space-y-6">
              <div className="flex items-center justify-between">
                <div className="flex space-x-2 bg-slate-900/80 p-1.5 rounded-2xl border border-slate-800 shadow-xl">
                  <button onClick={() => setActiveTab('live')} className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'live' ? 'bg-blue-600 text-white shadow-[0_0_20px_rgba(37,99,235,0.4)]' : 'text-slate-500 hover:text-slate-300'}`}>
                    <i className="fas fa-video mr-2"></i> Jonli Kamera
                  </button>
                  <button onClick={() => fileInputRef.current?.click()} className="px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-500 hover:text-slate-300 transition-all">
                    <i className="fas fa-cloud-arrow-up mr-2"></i> Yuklash
                  </button>
                  <input type="file" ref={fileInputRef} onChange={handleManualUpload} className="hidden" accept="image/*" />
                </div>
                <div className="flex items-center space-x-4 bg-slate-900/50 px-4 py-2 rounded-2xl border border-slate-800">
                   <div className="flex flex-col text-right">
                      <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest leading-none mb-1">AI Skaner</span>
                      <span className={`text-[10px] font-bold ${quotaError ? 'text-red-500' : 'text-emerald-500 animate-pulse'}`}>{quotaError ? 'TO\'XTADI' : 'AKTIV'}</span>
                   </div>
                   <div className={`w-8 h-8 rounded-full ${quotaError ? 'bg-red-500/10' : 'bg-emerald-500/10'} flex items-center justify-center border ${quotaError ? 'border-red-500/20' : 'border-emerald-500/20'}`}>
                      <i className={`fas ${quotaError ? 'fa-triangle-exclamation text-red-500' : 'fa-brain text-emerald-500'} text-xs`}></i>
                   </div>
                </div>
              </div>

              <div className="relative group">
                <LiveVision isActive={activeTab === 'live'} onAnalysisUpdate={handleLiveUpdate} onError={(msg) => msg === "QUOTA_EXHAUSTED" && setQuotaError(true)} />
                {isAnalyzing && (
                  <div className="absolute inset-0 bg-black/60 backdrop-blur-sm z-20 flex flex-col items-center justify-center rounded-[2rem]">
                    <div className="w-16 h-16 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin mb-4"></div>
                    <p className="text-blue-500 font-black uppercase tracking-[0.3em] text-xs">Neural Tahlil...</p>
                  </div>
                )}
              </div>

              {lastAnalysis && (
                <div className="bg-slate-900 border border-slate-800 rounded-[2.5rem] p-8 shadow-2xl relative overflow-hidden animate-slide-up group">
                  <div className="absolute -top-12 -right-12 w-48 h-48 bg-blue-600/5 rounded-full blur-3xl group-hover:bg-blue-600/10 transition-colors"></div>
                  <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8 relative z-10">
                    <div className="flex items-center space-x-5">
                      <div className={`text-2xl font-black px-6 py-2.5 rounded-2xl ${lastAnalysis.health === RoadHealth.POOR ? 'bg-red-500 shadow-[0_0_30px_rgba(239,68,68,0.3)]' : 'bg-emerald-500 shadow-[0_0_30px_rgba(16,185,129,0.3)]'}`}>
                        {lastAnalysis.health}
                      </div>
                      <div>
                        <h2 className="text-2xl font-black text-white uppercase tracking-tight leading-none mb-2">{lastAnalysis.type}</h2>
                        <p className="text-slate-500 text-[10px] font-black uppercase tracking-[0.2em]">Aniqlangan Yo'l Holati</p>
                      </div>
                    </div>
                    <div className="bg-slate-800/50 backdrop-blur-md px-6 py-3 rounded-2xl border border-slate-700 flex items-center space-x-3">
                       <i className="fas fa-triangle-exclamation text-amber-500"></i>
                       <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Xavf:</span>
                       <span className="text-sm font-black text-white">{lastAnalysis.severity}</span>
                    </div>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8 relative z-10">
                    <div className="space-y-3">
                      <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center">
                        <i className="fas fa-file-invoice mr-2"></i> To'liq Tavsif
                      </p>
                      <div className="bg-black/20 p-5 rounded-2xl border border-white/5">
                        <p className="text-sm text-slate-300 leading-relaxed font-medium">{lastAnalysis.description}</p>
                      </div>
                    </div>
                    <div className="space-y-3">
                      <p className="text-[10px] font-black text-blue-500 uppercase tracking-widest flex items-center">
                        <i className="fas fa-shield-heart mr-2"></i> Xavfsizlik Tavsiyasi
                      </p>
                      <div className="bg-blue-600/5 p-5 rounded-2xl border border-blue-500/10">
                        <p className="text-sm text-blue-300 leading-relaxed font-bold italic">"{lastAnalysis.recommendation}"</p>
                      </div>
