            <div className="lg:col-span-5 flex flex-col space-y-6">
              <div className="bg-slate-900/80 border border-slate-800 rounded-[2.5rem] p-6 shadow-2xl backdrop-blur-md">
                <div className="flex items-center justify-between mb-6">
                  <h3 className="text-xs font-black text-white uppercase tracking-[0.2em] flex items-center">
                    <i className="fas fa-map-location-dot mr-3 text-blue-500"></i> Smart Navigator
                  </h3>
                  {routeInfo && <span className="text-[9px] font-black text-emerald-500 bg-emerald-500/10 px-3 py-1 rounded-full uppercase">Optimal Yo'l Topildi</span>}
                </div>
                <form onSubmit={handleSearchAddress} className="relative mb-6">
                  <input 
                    type="text" 
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    placeholder="Manzilni kiriting..." 
                    className="w-full bg-slate-800/80 border border-slate-700 rounded-2xl py-5 pl-14 pr-4 text-sm text-white focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition-all font-medium"
                  />
                  <span className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-500 text-xl">
                    <i className={isSearching ? 'fas fa-spinner fa-spin text-blue-500' : 'fas fa-magnifying-glass'}></i>
                  </span>
                </form>
                {routeInfo && (
                  <div className="grid grid-cols-2 gap-4 animate-fade-in">
